  var require_chocolate_eclairs = __commonJS({
    "src/data/chocolate-eclairs.md"(exports, module) {
      module.exports = "# Chocolate Eclairs\n\n- **Servings:** {9}\n- **Yield:** {9} eclairs\n\n## Ingredients\n\n- {2} cup Milk\n- {1/2} Vanilla Bean, split lengthwise\n- {6} Egg Yolk\n- {2/3} cup Sugar\n- {1/4} cup Cornstarch\n- {1} tbsp Butter\n- {1} cup Water\n- {1} stick Butter\n- {1/2} tsp Salt\n- {1 1/2} tsp Sugar\n- {1} cup All-purpose Flour\n- {3} Egg\n- {1} Egg\n- {1 1/2} tsp Water\n- {1/2} cup Heavy Cream\n- {4} oz Semisweet Chocolate, chopped\n\n## Instructions\n\n1. Filling (first 6 ingredients): In a medium saucepan, heat the milk and vanilla bean to a boil over medium heat\n1. Immediately turn off the heat and set aside to infuse for 15 minutes\n1. In a bowl, whisk the egg yolks and sugar until light and fluffy\n1. Add the cornstarch and whisk vigorously until no lumps remain\n1. Whisk in 1/4 cup of the hot milk mixture until incorporated\n1. Whisk in the remaining hot milk mixture, reserving the saucepan\n1. Pour the mixture through a strainer back into the saucepan\n1. Cook over medium-high heat, whisking constantly, until thickened and slowly boiling\n1. Remove from the heat and stir in the butter\n1. Let cool slightly\n1. Cover with plastic wrap, lightly pressing the plastic against the surface to prevent a skin from forming\n1. Chill at least 2 hours or until ready to serve\n1. The custard can be made up to 24 hours in advance\n1. Refrigerate until 1 hour before using\n1. Pastry (next 6 ingredients): Preheat the oven to 425 degrees\n1. Line a sheet pan with parchment paper\n1. In a large saucepan, bring the water, butter, salt and sugar to a rolling boil over medium-high heat\n1. When it boils, immediately take the pan off the heat\n1. Stirring with a wooden spoon, add all the flour at once and stir hard until all the flour is incorporated, 30 to 60 seconds\n1. Return to the heat and cook, stirring, 30 seconds\n1. Scrape the mixture into a mixer fitted with a paddle attachment (or use a hand mixer)\n1. Mix at medium speed\n1. With the mixer running, add 3 eggs, 1 egg at a time\n1. Stop mixing after each addition to scrape down the sides of the bowl\n1. Mix until the dough is smooth and glossy and the eggs are completely incorporated\n1. The dough should be thick, but should fall slowly and steadily from the beaters when you lift them out of the bowl\n1. If the dough is still clinging to the beaters, add an extra egg and mix until incorporated\n1. Using a pastry bag fitted with a large plain tip, pipe fat lengths of dough (about the size and shape of a jumbo hot dog) onto the lined baking sheet, leaving 2 inches of space between them\n1. You should have 8 to 10 lengths\n1. Egg Wash (next 2 ingredients): In a bowl, whisk the egg and water together\n1. Brush the surface of each eclair with the egg wash\n1. Use your fingers to smooth out any bumps of points of dough that remain on the surface\n1. Bake 15 minutes, then reduce the heat to 375 degrees and bake until puffed up and light golden brown, about 25 minutes more\n1. Try not to open the oven door too often during the baking\n1. Let cool on the baking sheet\n1. Fit a medium-size plain pastry tip over your index finger and use it to make a hole in the end of each eclair (or just use your fingertip)\n1. Using a pastry bag fitted with a medium-size plain tip, gently pipe the custard into the eclairs, using only just enough to fill the inside (don't stuff them full)\n1. Glaze (last 2 ingredients): In a small saucepan, heat the cream over medium heat just until it boils\n1. Immediately turn off the heat\n1. Put the chocolate in a medium bowl\n1. Pour the hot cream over the chocolate and whisk until melted and smooth\n1. Set aside and keep warm\n1. The glaze can be made up to 48 hours in advance\n1. Cover and refrigerate until ready to use, and rewarm in a microwave or over hot water when ready to use\n1. Dip the tops of the eclairs in the warm chocolate glaze and set on a sheet pan\n1. Chill, uncovered, at least 1 hour to set the glaze\n1. Serve chilled\n";
    }
  });

