  var require_vanilla_fudge = __commonJS({
    "src/data/vanilla-fudge.md"(exports, module) {
      module.exports = "# Vanilla Fudge\n\n- **Servings:** {32}\n- **Yield:** {64} pieces\n\n## Ingredients\n\n- {1} tbsp Butter\n- {1 1/2} cup Heavy Cream\n- {3} cup Sugar\n- {1/4} cup Light Corn Syrup\n- {1/4} tsp Salt\n\n## Instructions\n\n1. Butter an 8-inch square baking pan; line with parchment paper, allowing a 1-inch overhang\n1. Butter parchment paper, and set aside\n1. Check the calibration of the candy thermometer\n1. Put butter into a large bowl, and set over a wire rack; set aside\n1. Put cream, sugar, corn syrup, and salt into a medium heavy saucepan\n1. Cook over medium-low heat, stirring constantly, until sugar has dissolved, about 10 minutes\n1. Raise heat to medium\n1. Bring mixture to a boil, washing down sides of pan with a wet pastry brush to prevent sugar crystals from forming\n1. Attach warm thermometer to pan; continue to cook, without stirring, until mixture registers 238 degrees (soft-ball stage), 10 to 15 minutes\n1. Immediately pour mixture into bowl with butter (do not scrape out the bottom of the pan)\n1. Attach thermometer to bowl\n1. Let mixture cool, undisturbed, until it registers 110 degrees, about 1 1/2 hours\n1. Remove thermometer\n1. Transfer bowl to a work surface\n1. Using a wooden spoon, begin to gently stir mixture\n1. Continue to stir, gradually increasing speed until mixture thickens, lightens in color, and loses its sheen, 4 to 5 minutes\n1. Pour into prepared pan\n1. Using a small offset spatula, quickly spread fudge to sides of pan, and smooth top\n1. Let fudge cool in pan on a wire rack, about 1 hour\n1. Cover with plastic, and refrigerate until completely set, about 8 hours\n1. Run a sharp knife around nonparchment sides to loosen; lift fudge out\n1. Cut into 64 one-inch pieces\n";
    }
  });

